361→```rust
362→//! Prompt configuration loader for review specialists.
363→//!
364→//! Loads specialist prompts from `.forge/autoresearch/prompts/<specialist>.md`
365→//! files, falling back to hardcoded defaults when no file exists.
366→
367→use crate::review::SpecialistType;
368→use serde::{Deserialize, Serialize};
369→use std::path::{Path, PathBuf};
370→use tracing::{debug, warn};
371→
372→/// Mode of a review specialist prompt (informational only).
373→///
374→/// This field is stored in YAML frontmatter for human readability.
375→/// **Gating behavior is determined by `SpecialistType::default_gating()`,
376→/// NOT by this field.**
377→#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
378→#[serde(rename_all = "lowercase")]
379→pub enum PromptMode {
380→    Gating,
381→    Advisory,
382→}
383→
384→/// Parsed prompt configuration for a review specialist.
385→///
386→/// Combines YAML frontmatter metadata with the markdown prompt body.
387→#[derive(Debug, Clone, Serialize, Deserialize)]
388→pub struct PromptConfig {
389→    /// Specialist name from frontmatter (e.g., "SecuritySentinel").
390→    pub specialist_name: String,
391→    /// Mode (informational only -- does NOT control gating).
392→    pub mode: PromptMode,
393→    /// Focus areas parsed from the markdown body's "## Focus Areas" section.
394→    pub focus_areas: Vec<String>,
395→    /// The full markdown body (everything after the YAML frontmatter).
396→    pub body: String,
397→}
398→
399→/// YAML frontmatter structure for deserialization.
400→#[derive(Debug, Deserialize)]
401→struct PromptFrontmatter {
402→    specialist: String,
403→    #[serde(default = "default_mode")]
404→    mode: String,
405→}
406→
407→fn default_mode() -> String {
408→    "advisory".to_string()
409→}
410→
411→/// Loader that resolves specialist prompts from files or hardcoded defaults.
412→pub struct PromptLoader {
413→    /// Root directory (the `.forge` directory or equivalent).
414→    forge_dir: PathBuf,
415→}
416→```
