  1→//! Design document implementation module for forge.
  2→//!
  3→//! This module provides the `forge implement` command which takes a design
  4→//! document and implements it end-to-end using TDD-first phase generation.
  5→//!
  6→//! The workflow:
  7→//! 1. Parse and validate the design document
  8→//! 2. Extract implementation spec and phases via Claude
  9→//! 3. Generate spec.md and phases.json
 10→//! 4. Interactive review and approval
 11→//! 5. Execute phases using the standard orchestrator
 12→
 13→pub mod extract;
 14→pub mod spec_gen;
 15→pub mod types;
 16→
 17→pub use extract::{DESIGN_DOC_EXTRACTION_PROMPT, extract_design, validate_design_doc};
 18→pub use spec_gen::generate_spec_markdown;
 19→pub use types::{CodePattern, Complexity, Component, ExtractedDesign, ExtractedSpec};
 20→
 21→use anyhow::{Context, Result};
 22→use dialoguer::Input;
 23→use std::path::Path;
 24→
 25→use crate::generate::{ReviewAction, create_phases_file, parse_review_action};
 26→use crate::init::get_forge_dir;
 27→use crate::phase::{Phase, PhaseType};
 28→
 29→/// Run the implement command.
 30→///
 31→/// This is the main entry point for `forge implement <design-doc>`.
 32→///
 33→/// # Arguments
 34→/// * `project_dir` - The project root directory
 35→/// * `design_doc` - Path to the design document
 36→/// * `no_tdd` - Skip test phase generation
 37→/// * `dry_run` - Generate spec and phases without executing
 38→///
 39→/// # Returns
 40→/// `Ok(())` on success, or an error if something fails.
 41→pub fn run_implement(
 42→    project_dir: &Path,
 43→    design_doc: &Path,
 44→    no_tdd: bool,
 45→    dry_run: bool,
 46→) -> Result<()> {
 47→    // 1. Validate and read design doc
 48→    println!("Parsing design doc...");
 49→    let design_content = validate_design_doc(design_doc)?;
 50→
 51→    // 2. Extract structure via Claude
 52→    println!("Extracting implementation details...");
 53→    let extracted = extract_design(project_dir, &design_content, design_doc)?;
 54→
 55→    // 3. Filter out test phases if --no-tdd and renumber
 56→    let phases = filter_phases(extracted.phases, no_tdd);
 57→
 58→    // 4. Generate spec.md
 59→    println!("Generating implementation spec...");
 60→    let spec_content = generate_spec_markdown(&extracted.spec);
 61→    let forge_dir = get_forge_dir(project_dir);
 62→
 63→    // Ensure .forge directory exists
 64→    if !forge_dir.exists() {
 65→        std::fs::create_dir_all(&forge_dir).context("Failed to create .forge directory")?;
 66→    }
 67→
 68→    std::fs::write(forge_dir.join("spec.md"), &spec_content).context("Failed to write spec.md")?;
 69→
 70→    // 5. Save phases.json
 71→    println!("Generating phases...");
 72→    let phases_file = create_phases_file(phases.clone(), &spec_content);
 73→    phases_file
 74→        .save(&forge_dir.join("phases.json"))
 75→        .context("Failed to write phases.json")?;
 76→
 77→    // 6. Display phases
 78→    display_phases_with_type(&phases);
 79→
 80→    if dry_run {
 81→        println!();
 82→        println!("Dry run complete. Review:");
 83→        println!("  Spec: .forge/spec.md");
 84→        println!("  Phases: .forge/phases.json");
 85→        return Ok(());
 86→    }
 87→
 88→    // 7. Interactive review
 89→    loop {
 90→        println!("[a]pprove  [e]dit phase  [r]egenerate  [q]uit");
 91→
 92→        let input: String = Input::new()
 93→            .with_prompt(">")
 94→            .allow_empty(false)
 95→            .interact_text()
 96→            .context("Failed to read user input")?;
 97→
 98→        match parse_review_action(&input)? {
 99→            ReviewAction::Approve => {
100→                println!();
101→                println!("Phases approved. Run 'forge run' to start execution.");
102→                return Ok(());
103→            }
104→            ReviewAction::EditPhase(phase_num) => {
105→                println!(
106→                    "\nEditing phase {} - please provide feedback and regenerate.",
107→                    phase_num
108→                );
109→                println!("Phase editing is not yet fully implemented.");
110→                continue;
111→            }
112→            ReviewAction::Regenerate => {
113→                println!("\nRegenerating...");
114→                // Re-extract
115→                let extracted = extract_design(project_dir, &design_content, design_doc)?;
116→                let phases = filter_phases(extracted.phases, no_tdd);
117→
118→                // Update spec and phases
119→                let spec_content = generate_spec_markdown(&extracted.spec);
120→                std::fs::write(forge_dir.join("spec.md"), &spec_content)
121→                    .context("Failed to write spec.md during regeneration")?;
122→
123→                let phases_file = create_phases_file(phases.clone(), &spec_content);
124→                phases_file
125→                    .save(&forge_dir.join("phases.json"))
126→                    .context("Failed to write phases.json during regeneration")?;
127→
128→                display_phases_with_type(&phases);
129→                continue;
130→            }
131→            ReviewAction::Quit => {
132→                println!("\nExiting without changes.");
133→                return Ok(());
134→            }
135→        }
136→    }
137→}
138→
139→/// Display phases with their type (test/implement) indicator.
140→fn display_phases_with_type(phases: &[Phase]) {
141→    println!();
142→    for phase in phases {
143→        let type_tag = match phase.phase_type {
144→            Some(PhaseType::Test) => "[test]",
145→            Some(PhaseType::Implement) => "[implement]",
146→            None => "",
147→        };
148→
149→        println!(
150→            "Phase {}: {} (budget: {}) {}",
151→            phase.number, phase.name, phase.budget, type_tag
152→        );
153→    }
154→    println!();
155→}
156→
157→/// Filter phases based on TDD setting and renumber them.
158→///
159→/// If `no_tdd` is true, test phases are filtered out.
160→/// The remaining phases are then renumbered sequentially.
161→fn filter_phases(phases: Vec<Phase>, no_tdd: bool) -> Vec<Phase> {
162→    let filtered = if no_tdd {
163→        phases
164→            .into_iter()
165→            .filter(|p| p.phase_type != Some(PhaseType::Test))
166→            .collect()
167→    } else {
168→        phases
169→    };
170→    renumber_phases(filtered)
171→}
172→
173→/// Renumber phases sequentially after filtering.
174→///
175→/// When --no-tdd filters out test phases, we need to renumber
176→/// the remaining phases to be sequential (01, 02, 03...) and
177→/// update their dependencies accordingly.
178→fn renumber_phases(phases: Vec<Phase>) -> Vec<Phase> {
179→    if phases.is_empty() {
180→        return phases;
181→    }
182→
183→    // Build a mapping from old number to new number
184→    let mut number_map: std::collections::HashMap<String, String> =
185→        std::collections::HashMap::new();
186→    for (i, phase) in phases.iter().enumerate() {
187→        let new_number = format!("{:02}", i + 1);
188→        number_map.insert(phase.number.clone(), new_number);
189→    }
190→
191→    // Apply the mapping
192→    phases
193→        .into_iter()
194→        .enumerate()
195→        .map(|(i, mut phase)| {
196→            let new_number = format!("{:02}", i + 1);
197→
198→            // Update dependencies to use new numbers
199→            phase.depends_on = phase
200→                .depends_on
201→                .into_iter()
202→                .filter_map(|dep| number_map.get(&dep).cloned())
203→                .collect();
204→
205→            phase.number = new_number;
206→            phase
207→        })
208→        .collect()
209→}
