  1→//! Phase generation module for forge.
  2→//!
  3→//! This module provides the `forge generate` functionality to generate implementation
  4→//! phases from a project specification. It uses Claude to analyze the spec and propose
  5→//! a set of implementation phases with budgets, promises, and dependencies.
  6→//!
  7→//! The generated phases are saved to `.forge/phases.json`.
  8→
  9→use anyhow::{Context, Result, bail};
 10→use sha2::{Digest, Sha256};
 11→use std::path::Path;
 12→use std::process::{Command, Stdio};
 13→
 14→use crate::forge_config::ForgeConfig;
 15→use crate::init::{get_forge_dir, is_initialized};
 16→use crate::phase::{Phase, PhasesFile};
 17→use crate::util::extract_json_object;
 18→
 19→/// The system prompt used for generating phases from a spec.
 20→pub const GENERATION_SYSTEM_PROMPT: &str = r#"You are generating implementation phases from a project specification.
 21→
 22→Given the following project spec, generate a list of implementation phases.
 23→Each phase should:
 24→- Have a clear, achievable goal
 25→- Include a promise tag (format: "NAME COMPLETE")
 26→- Have a reasonable iteration budget (5-30)
 27→- Include reasoning explaining why this phase is needed
 28→- List dependencies on other phases by number
 29→
 30→Output ONLY the phases as JSON in this exact format (no other text):
 31→{
 32→  "phases": [
 33→    {
 34→      "number": "01",
 35→      "name": "Phase Name",
 36→      "promise": "NAME COMPLETE",
 37→      "budget": 10,
 38→      "reasoning": "Why this phase is needed",
 39→      "depends_on": []
 40→    }
 41→  ]
 42→}
 43→
 44→Guidelines:
 45→- Number phases starting from "01" with zero-padded two digits
 46→- Promises should be in the format "UPPERCASE COMPLETE"
 47→- Budget should be between 5 and 30 iterations
 48→- Early phases (scaffold, config) should have smaller budgets (5-10)
 49→- Complex phases (auth, integrations) should have larger budgets (15-25)
 50→- Identify natural dependencies - what must be done before what
 51→- Include all major features from the spec
 52→- Order phases logically with dependencies"#;
 53→
 54→/// Result of parsing phases from Claude's output.
 55→#[derive(Debug)]
 56→pub struct ParsedPhases {
 57→    pub phases: Vec<Phase>,
 58→}
 59→
 60→/// Compute a SHA256 hash of the spec content.
 61→///
 62→/// This is used to track which version of the spec was used to generate phases.
 63→///
 64→/// # Arguments
 65→/// * `content` - The spec file content
 66→///
 67→/// # Returns
 68→/// A hex-encoded SHA256 hash string (truncated to 12 characters).
 69→pub fn compute_spec_hash(content: &str) -> String {
 70→    let mut hasher = Sha256::new();
 71→    hasher.update(content.as_bytes());
 72→    let result = hasher.finalize();
 73→    // Return first 12 hex characters for brevity
 74→    format!("{:x}", result)[..12].to_string()
 75→}
 76→
 77→/// Parse phases JSON from Claude's output.
 78→///
 79→/// Claude may include extra text before/after the JSON, so we need to extract
 80→/// the JSON object from the output.
 81→///
 82→/// # Arguments
 83→/// * `output` - The raw output from Claude
 84→///
 85→/// # Returns
 86→/// `ParsedPhases` containing the extracted phases, or an error if parsing fails.
 87→pub fn parse_phases_from_output(output: &str) -> Result<ParsedPhases> {
 88→    // Find the JSON object in the output
 89→    let json_str = extract_json_object(output)
 90→        .ok_or_else(|| anyhow::anyhow!("No JSON object found in Claude's output"))?;
 91→
 92→    // Parse the JSON
 93→    let parsed: serde_json::Value =
 94→        serde_json::from_str(&json_str).context("Failed to parse JSON from Claude's output")?;
 95→
 96→    // Extract the phases array
 97→    let phases_array = parsed
 98→        .get("phases")
 99→        .ok_or_else(|| anyhow::anyhow!("No 'phases' field in JSON output"))?
100→        .as_array()
101→        .ok_or_else(|| anyhow::anyhow!("'phases' field is not an array"))?;
102→
103→    // Parse each phase
104→    let mut phases = Vec::new();
105→    for (i, phase_value) in phases_array.iter().enumerate() {
106→        let phase: Phase = serde_json::from_value(phase_value.clone())
107→            .with_context(|| format!("Failed to parse phase {} from JSON", i + 1))?;
108→        phases.push(phase);
109→    }
110→
111→    Ok(ParsedPhases { phases })
112→}
113→
114→/// Create a PhasesFile from parsed phases and spec content.
115→///
116→/// # Arguments
117→/// * `phases` - The parsed phases
118→/// * `spec_content` - The original spec content (for computing the hash)
119→///
120→/// # Returns
121→/// A `PhasesFile` ready to be saved.
122→pub fn create_phases_file(phases: Vec<Phase>, spec_content: &str) -> PhasesFile {
123→    let spec_hash = compute_spec_hash(spec_content);
124→    let generated_at = chrono::Utc::now().to_rfc3339();
125→
126→    PhasesFile {
127→        spec_hash,
128→        generated_at,
129→        phases,
130→    }
131→}
132→
133→/// Read the spec file from the .forge directory.
134→///
135→/// # Arguments
136→/// * `project_dir` - The project root directory
137→///
138→/// # Returns
139→/// The content of the spec file, or an error if not found.
140→pub fn read_spec(project_dir: &Path) -> Result<String> {
141→    let forge_dir = get_forge_dir(project_dir);
142→    let spec_file = forge_dir.join("spec.md");
143→
144→    if !spec_file.exists() {
145→        bail!(
146→            "Spec file not found at {}. Run 'forge interview' first.",
147→            spec_file.display()
148→        );
149→    }
150→
151→    let content = std::fs::read_to_string(&spec_file)
152→        .with_context(|| format!("Failed to read spec file: {}", spec_file.display()))?;
153→
154→    if content.trim().is_empty() {
155→        bail!(
156→            "Spec file is empty at {}. Run 'forge interview' to create your spec.",
157→            spec_file.display()
158→        );
159→    }
160→
161→    Ok(content)
162→}
163→
164→/// Call Claude to generate phases from a spec.
165→///
166→/// Uses the `--print` mode for a stateless call.
167→///
168→/// # Arguments
169→/// * `project_dir` - The project root directory
170→/// * `spec_content` - The spec content to send to Claude
171→///
172→/// # Returns
173→/// The raw output from Claude.
174→pub fn call_claude_for_phases(project_dir: &Path, spec_content: &str) -> Result<String> {
175→    // Get claude_cmd from unified configuration
176→    let claude_cmd = ForgeConfig::new(project_dir.to_path_buf())
177→        .map(|c| c.claude_cmd())
178→        .unwrap_or_else(|_| std::env::var("CLAUDE_CMD").unwrap_or_else(|_| "claude".to_string()));
179→
180→    // Build the prompt
181→    let prompt = format!(
182→        "{}\n\n## Project Spec\n\n{}",
183→        GENERATION_SYSTEM_PROMPT, spec_content
184→    );
185→
186→    let mut cmd = Command::new(&claude_cmd);
187→    cmd.arg("--print");
188→    cmd.arg("--no-session-persistence");
189→    cmd.arg("-p");
190→    cmd.arg(&prompt);
191→    cmd.current_dir(project_dir);
192→    cmd.stdout(Stdio::piped());
193→    cmd.stderr(Stdio::piped());
194→
195→    let output = cmd
196→        .output()
197→        .context("Failed to execute Claude command. Is 'claude' in your PATH?")?;
198→
199→    if !output.status.success() {
200→        let stderr = String::from_utf8_lossy(&output.stderr);
201→        bail!("Claude command failed: {}", stderr);
202→    }
203→
204→    let stdout = String::from_utf8_lossy(&output.stdout).to_string();
205→    Ok(stdout)
206→}
