208→/// Display phases for user review.
209→///
210→/// # Arguments
211→/// * `phases` - The phases to display
212→pub fn display_phases(phases: &[Phase]) {
213→    println!();
214→    for phase in phases {
215→        println!(
216→            "Phase {}: {} (budget: {})",
217→            phase.number, phase.name, phase.budget
218→        );
219→        println!("  Promise: {}", phase.promise);
220→        println!("  Reason: {}", phase.reasoning);
221→        if !phase.depends_on.is_empty() {
222→            println!("  Depends on: {}", phase.depends_on.join(", "));
223→        }
224→        println!();
225→    }
226→}
