228→/// Interactive review options for the user.
229→#[derive(Debug, Clone, PartialEq)]
230→pub enum ReviewAction {
231→    Approve,
232→    EditPhase(String),
233→    Regenerate,
234→    Quit,
235→}
236→
237→/// Parse user input for review action.
238→///
239→/// # Arguments
240→/// * `input` - The user's input string
241→///
242→/// # Returns
243→/// The parsed `ReviewAction`, or an error if invalid.
244→pub fn parse_review_action(input: &str) -> Result<ReviewAction> {
245→    let input = input.trim().to_lowercase();
246→
247→    if input == "a" || input == "approve" {
248→        return Ok(ReviewAction::Approve);
249→    }
250→
251→    if input == "r" || input == "regenerate" {
252→        return Ok(ReviewAction::Regenerate);
253→    }
254→
255→    if input == "q" || input == "quit" {
256→        return Ok(ReviewAction::Quit);
257→    }
258→
259→    if input == "e" || input == "edit" {
260→        bail!("Please specify a phase number to edit, e.g., 'e 01' or 'edit 02'");
261→    }
262→
263→    if input.starts_with("e ") || input.starts_with("edit ") {
264→        let phase_num = input
265→            .trim_start_matches("edit ")
266→            .trim_start_matches("e ")
267→            .trim();
268→        if phase_num.is_empty() {
269→            bail!("Please specify a phase number to edit, e.g., 'e 01' or 'edit 02'");
270→        }
271→        return Ok(ReviewAction::EditPhase(phase_num.to_string()));
272→    }
273→
274→    bail!("Invalid action. Use [a]pprove, [e]dit <phase>, [r]egenerate, or [q]uit");
275→}
276→
277→/// Run the phase generation workflow.
278→///
279→/// This is the main entry point for `forge generate`.
280→///
281→/// # Arguments
282→/// * `project_dir` - The project root directory
283→/// * `spec_file` - Optional path to a spec file. If not provided, defaults to `.forge/spec.md`
284→/// * `auto_approve` - If true, automatically approve generated phases without prompting
285→///
286→/// # Returns
287→/// `Ok(())` on success, or an error if something fails.
288→pub fn run_generate(
289→    project_dir: &Path,
290→    spec_file: Option<&Path>,
291→    auto_approve: bool,
292→) -> Result<()> {
293→    use crate::patterns::{
294→        display_budget_suggestions, display_pattern_matches, list_patterns, match_patterns,
295→        suggest_budgets,
296→    };
297→    use dialoguer::Input;
298→
299→    // Check if project is initialized
300→    if !is_initialized(project_dir) {
301→        bail!("Project not initialized. Run 'forge init' first to create the .forge/ directory.");
302→    }
303→
304→    // Read spec - from provided file or default location
305→    let spec_content = if let Some(spec_path) = spec_file {
306→        println!("Reading spec from {}...", spec_path.display());
307→        std::fs::read_to_string(spec_path)
308→            .with_context(|| format!("Failed to read spec file: {}", spec_path.display()))?
309→    } else {
310→        println!("Reading spec from .forge/spec.md...");
311→        read_spec(project_dir)?
312→    };
313→
314→    if spec_content.trim().is_empty() {
315→        bail!("Spec file is empty. Please provide a valid spec file.");
316→    }
317→
318→    // Check for similar patterns
319→    let all_patterns = list_patterns().unwrap_or_default();
320→    let pattern_matches = match_patterns(&spec_content, &all_patterns);
321→
322→    if !pattern_matches.is_empty() {
323→        display_pattern_matches(&pattern_matches);
324→    }
325→
326→    // Main loop for generation and review
327→    loop {
328→        // Generate phases
329→        println!("Generating phases...");
330→        let claude_output = call_claude_for_phases(project_dir, &spec_content)?;
331→
332→        // Parse phases from output
333→        let parsed = parse_phases_from_output(&claude_output)?;
334→
335→        // Display phases
336→        display_phases(&parsed.phases);
337→
338→        // If we have similar patterns, show budget suggestions
339→        if !pattern_matches.is_empty() {
340→            let similar_patterns: Vec<_> = pattern_matches
341→                .iter()
342→                .filter(|m| m.score > 0.3)
343→                .take(3)
344→                .map(|m| m.pattern)
345→                .collect();
346→
347→            if !similar_patterns.is_empty() {
348→                let suggestions = suggest_budgets(&similar_patterns, &parsed.phases);
349→                display_budget_suggestions(&suggestions);
350→            }
351→        }
352→
353→        // Auto-approve if flag is set
354→        if auto_approve {
355→            let forge_dir = get_forge_dir(project_dir);
356→            let phases_file_path = forge_dir.join("phases.json");
357→            let phases_file = create_phases_file(parsed.phases, &spec_content);
358→            phases_file.save(&phases_file_path)?;
359→            println!(
360→                "\nPhases automatically approved and saved to {}",
361→                phases_file_path.display()
362→            );
363→            return Ok(());
364→        }
365→
366→        // Show options
367→        println!("[a]pprove  [e]dit phase  [r]egenerate  [q]uit");
368→
369→        // Get user input
370→        let input: String = Input::new()
371→            .with_prompt(">")
372→            .allow_empty(false)
373→            .interact_text()
374→            .context("Failed to read user input")?;
375→
376→        match parse_review_action(&input)? {
377→            ReviewAction::Approve => {
378→                // Save phases
379→                let forge_dir = get_forge_dir(project_dir);
380→                let phases_file_path = forge_dir.join("phases.json");
381→                let phases_file = create_phases_file(parsed.phases, &spec_content);
382→                phases_file.save(&phases_file_path)?;
383→                println!("\nPhases saved to {}", phases_file_path.display());
384→                return Ok(());
385→            }
386→            ReviewAction::EditPhase(phase_num) => {
387→                // For now, just tell user to regenerate with feedback
388→                println!(
389→                    "\nEditing phase {} - please provide feedback and regenerate.",
390→                    phase_num
391→                );
392→                println!("Phase editing is not yet fully implemented.");
393→                continue;
394→            }
395→            ReviewAction::Regenerate => {
396→                println!("\nRegenerating phases...");
397→                continue;
398→            }
399→            ReviewAction::Quit => {
400→                println!("\nExiting without saving.");
401→                return Ok(());
402→            }
403→        }
404→    }
405→}
