141→        }
142→    }
143→
144→    pub fn finish(&mut self, outcome: PhaseOutcome, changes: FileChangeSummary) {
145→        self.ended_at = Some(Utc::now());
146→        self.outcome = outcome;
147→        self.file_changes = changes;
148→    }
149→
150→    /// Record a compaction event.
151→    pub fn add_compaction_event(
152→        &mut self,
153→        iterations_compacted: u32,
154→        original_chars: usize,
155→        summary_chars: usize,
156→    ) {
157→        let compression_ratio = if original_chars > 0 {
158→            1.0 - (summary_chars as f32 / original_chars as f32)
159→        } else {
160→            0.0
161→        };
162→
163→        self.compaction_events.push(CompactionEvent {
164→            timestamp: Utc::now(),
165→            iterations_compacted,
166→            original_chars,
167→            summary_chars,
168→            compression_ratio,
169→        });
170→    }
171→
172→    /// Check if this is a sub-phase audit.
173→    pub fn is_sub_phase(&self) -> bool {
174→        self.parent_phase.is_some()
175→    }
176→
177→    /// Check if this phase has any sub-phase audits.
178→    pub fn has_sub_phases(&self) -> bool {
179→        !self.sub_phase_audits.is_empty()
180→    }
181→
182→    /// Add a sub-phase audit to this phase.
183→    pub fn add_sub_phase_audit(&mut self, sub_audit: SubPhaseAudit) {
184→        self.sub_phase_audits.push(sub_audit);
185→    }
186→
187→    /// Get a sub-phase audit by number.
188→    pub fn get_sub_phase_audit(&self, number: &str) -> Option<&SubPhaseAudit> {
189→        self.sub_phase_audits
190→            .iter()
191→            .find(|spa| spa.sub_phase_number == number)
192→    }
193→
194→    /// Get a mutable sub-phase audit by number.
195→    pub fn get_sub_phase_audit_mut(&mut self, number: &str) -> Option<&mut SubPhaseAudit> {
196→        self.sub_phase_audits
197→            .iter_mut()
198→            .find(|spa| spa.sub_phase_number == number)
199→    }
200→
201→    /// Count total iterations including sub-phase iterations.
202→    pub fn total_iterations(&self) -> usize {
203→        self.iterations.len()
204→            + self
205→                .sub_phase_audits
206→                .iter()
207→                .map(|spa| spa.iterations.len())
208→                .sum::<usize>()
209→    }
210→
211→    /// Get aggregate file changes including sub-phases.
212→    pub fn total_file_changes(&self) -> FileChangeSummary {
213→        let mut summary = self.file_changes.clone();
214→        for spa in &self.sub_phase_audits {
215→            summary
216→                .files_added
217→                .extend(spa.file_changes.files_added.clone());
218→            summary
219→                .files_modified
220→                .extend(spa.file_changes.files_modified.clone());
221→            summary
222→                .files_deleted
223→                .extend(spa.file_changes.files_deleted.clone());
224→            summary.total_lines_added += spa.file_changes.total_lines_added;
225→            summary.total_lines_removed += spa.file_changes.total_lines_removed;
226→        }
227→        summary
228→    }
229→
230→    /// Check if all sub-phases completed successfully.
231→    pub fn all_sub_phases_completed(&self) -> bool {
232→        self.sub_phase_audits.is_empty()
233→            || self
234→                .sub_phase_audits
235→                .iter()
236→                .all(|spa| matches!(spa.outcome, PhaseOutcome::Completed { .. }))
237→    }
238→}
