240→impl SubPhaseAudit {
241→    /// Create a new sub-phase audit.
242→    pub fn new(
243→        sub_phase_number: &str,
244→        parent_phase: &str,
245→        description: &str,
246→        promise: &str,
247→        budget: u32,
248→    ) -> Self {
249→        Self {
250→            sub_phase_number: sub_phase_number.to_string(),
251→            parent_phase: parent_phase.to_string(),
252→            description: description.to_string(),
253→            promise: promise.to_string(),
254→            started_at: Utc::now(),
255→            ended_at: None,
256→            iterations: Vec::new(),
257→            outcome: PhaseOutcome::InProgress,
258→            file_changes: FileChangeSummary::default(),
259→            budget,
260→            iterations_used: 0,
261→        }
262→    }
263→
264→    /// Finish the sub-phase audit with final outcome.
265→    pub fn finish(&mut self, outcome: PhaseOutcome, changes: FileChangeSummary) {
266→        self.ended_at = Some(Utc::now());
267→        self.outcome = outcome;
268→        self.file_changes = changes;
269→        self.iterations_used = self.iterations.len() as u32;
270→    }
271→
272→    /// Add an iteration audit to this sub-phase.
273→    pub fn add_iteration(&mut self, iteration: IterationAudit) {
274→        self.iterations.push(iteration);
275→    }
276→
277→    /// Get duration in seconds.
278→    pub fn duration_secs(&self) -> Option<f64> {
279→        self.ended_at
280→            .map(|end| (end - self.started_at).num_milliseconds() as f64 / 1000.0)
281→    }
282→
283→    /// Check if this sub-phase completed successfully.
284→    pub fn is_successful(&self) -> bool {
285→        matches!(self.outcome, PhaseOutcome::Completed { .. })
286→    }
287→}
