  1→use super::{AuditRun, PhaseAudit, RunConfig};
  2→use anyhow::{Context, Result};
  3→use std::fs;
  4→use std::path::{Path, PathBuf};
  5→
  6→pub struct AuditLogger {
  7→    audit_dir: PathBuf,
  8→    current_run: Option<AuditRun>,
  9→    current_run_file: PathBuf,
 10→}
 11→
 12→impl AuditLogger {
 13→    pub fn new(audit_dir: &Path) -> Self {
 14→        let current_run_file = audit_dir.join("current-run.json");
 15→        Self {
 16→            audit_dir: audit_dir.to_path_buf(),
 17→            current_run: None,
 18→            current_run_file,
 19→        }
 20→    }
 21→
 22→    pub fn start_run(&mut self, config: RunConfig) -> Result<()> {
 23→        let run = AuditRun::new(config);
 24→        self.current_run = Some(run);
 25→        self.save_current()?;
 26→        Ok(())
 27→    }
 28→
 29→    /// Add a phase audit record to the current run.
 30→    ///
 31→    /// Returns an error if no run is currently active (i.e., `start_run` was never called
 32→    /// or `finish_run` has already been called). This prevents silent data loss when callers
 33→    /// forget to start a run before logging phase data.
 34→    pub fn add_phase(&mut self, phase: PhaseAudit) -> Result<()> {
 35→        let run = self
 36→            .current_run
 37→            .as_mut()
 38→            .ok_or_else(|| anyhow::anyhow!("add_phase called with no active run"))?;
 39→        run.phases.push(phase);
 40→        self.save_current()
 41→    }
 42→
 43→    /// Apply a mutation to the last phase in the current run.
 44→    ///
 45→    /// Returns an error if no run is currently active, or if the current run has no phases
 46→    /// yet. Both conditions indicate a programming error — the caller must ensure a run and
 47→    /// at least one phase exist before updating.
 48→    pub fn update_last_phase<F>(&mut self, f: F) -> Result<()>
 49→    where
 50→        F: FnOnce(&mut PhaseAudit),
 51→    {
 52→        let run = self
 53→            .current_run
 54→            .as_mut()
 55→            .ok_or_else(|| anyhow::anyhow!("update_last_phase called with no active run"))?;
 56→        let phase = run
 57→            .phases
 58→            .last_mut()
 59→            .ok_or_else(|| anyhow::anyhow!("update_last_phase called with no phases in run"))?;
 60→        f(phase);
 61→        self.save_current()
 62→    }
 63→
 64→    pub fn finish_run(&mut self) -> Result<PathBuf> {
 65→        let run = self
 66→            .current_run
 67→            .as_mut()
 68→            .ok_or_else(|| anyhow::anyhow!("No current run to finish"))?;
 69→
 70→        run.finish();
 71→
 72→        // Save to runs directory
 73→        let filename = format!(
 74→            "{}_{}.json",
 75→            run.started_at.format("%Y-%m-%dT%H-%M-%S"),
 76→            &run.run_id.to_string()[..8]
 77→        );
 78→        let run_file = self.audit_dir.join("runs").join(&filename);
 79→
 80→        let json = serde_json::to_string_pretty(&run).context("Failed to serialize audit run")?;
 81→        fs::write(&run_file, json).context("Failed to write audit run file")?;
 82→
 83→        // Remove current run file — propagate errors instead of silently discarding them
 84→        if self.current_run_file.exists() {
 85→            fs::remove_file(&self.current_run_file)
 86→                .context("Failed to remove current-run.json after finishing run")?;
 87→        }
 88→
 89→        self.current_run = None;
 90→        Ok(run_file)
 91→    }
 92→
 93→    pub fn save_current(&self) -> Result<()> {
 94→        if let Some(ref run) = self.current_run {
 95→            let json =
 96→                serde_json::to_string_pretty(&run).context("Failed to serialize current run")?;
 97→            fs::write(&self.current_run_file, json).context("Failed to write current run file")?;
 98→        }
 99→        Ok(())
100→    }
101→
102→    pub fn load_current(&mut self) -> Result<bool> {
103→        if self.current_run_file.exists() {
104→            let content = fs::read_to_string(&self.current_run_file)
105→                .context("Failed to read current run file")?;
106→            let run: AuditRun =
107→                serde_json::from_str(&content).context("Failed to parse current run file")?;
108→            self.current_run = Some(run);
109→            Ok(true)
110→        } else {
111→            Ok(false)
112→        }
113→    }
114→
115→    pub fn current_run(&self) -> Option<&AuditRun> {
116→        self.current_run.as_ref()
117→    }
118→
119→    pub fn list_runs(&self) -> Result<Vec<PathBuf>> {
120→        let runs_dir = self.audit_dir.join("runs");
121→        if !runs_dir.exists() {
122→            return Ok(Vec::new());
123→        }
124→
125→        let mut runs: Vec<PathBuf> = fs::read_dir(&runs_dir)?
126→            .filter_map(|e| e.ok())
127→            .map(|e| e.path())
128→            .filter(|p| p.extension().map(|e| e == "json").unwrap_or(false))
129→            .collect();
130→
131→        runs.sort();
132→        runs.reverse(); // Most recent first
133→        Ok(runs)
134→    }
135→
136→    pub fn load_run(&self, path: &Path) -> Result<AuditRun> {
137→        let content = fs::read_to_string(path).context("Failed to read audit run file")?;
138→        let run: AuditRun =
139→            serde_json::from_str(&content).context("Failed to parse audit run file")?;
140→        Ok(run)
141→    }
142→}
