  1→//! Initialization module for forge projects.
  2→//!
  3→//! This module provides the `forge init` functionality to create the `.forge/` directory
  4→//! structure in a project. The structure includes:
  5→//!
  6→//! ```text
  7→//! .forge/
  8→//! ├── spec.md          # Generated spec document (placeholder)
  9→//! ├── phases.json      # Generated phases with metadata (placeholder)
 10→//! ├── state            # Current execution state
 11→//! ├── audit/           # Run logs and audit trail
 12→//! │   └── runs/
 13→//! ├── prompts/         # Optional prompt overrides
 14→//! └── skills/          # Reusable prompt fragments (skills)
 15→//! ```
 16→
 17→use anyhow::{Context, Result};
 18→use std::path::{Path, PathBuf};
 19→
 20→/// The name of the forge configuration directory.
 21→pub const FORGE_DIR: &str = ".forge";
 22→
 23→/// Result of initializing a forge project.
 24→#[derive(Debug)]
 25→pub struct InitResult {
 26→    /// Path to the created .forge directory
 27→    pub forge_dir: PathBuf,
 28→    /// Whether the directory was newly created (false if it already existed)
 29→    pub created: bool,
 30→}
 31→
 32→/// Initialize a forge project in the given directory.
 33→///
 34→/// Creates the `.forge/` directory structure with placeholder files.
 35→///
 36→/// # Arguments
 37→/// * `project_dir` - The root directory of the project
 38→/// * `from_pattern` - Optional pattern template name to copy from
 39→///
 40→/// # Returns
 41→/// `InitResult` containing the path to the created directory and whether it was new.
 42→pub fn init_project(project_dir: &Path, from_pattern: Option<&str>) -> Result<InitResult> {
 43→    // Check for pattern template
 44→    // TODO: Future pattern template integration
 45→    // When a pattern name is provided via --from:
 46→    // 1. Look up the pattern in ~/.forge/patterns/
 47→    // 2. Copy the pattern's spec template to .forge/spec.md
 48→    // 3. Pre-populate phases.json based on pattern's phase_stats
 49→    // 4. Apply adaptive budget suggestions from pattern history
 50→    if let Some(pattern) = from_pattern {
 51→        anyhow::bail!(
 52→            "Pattern templates not yet implemented. Cannot use --from '{}'",
 53→            pattern
 54→        );
 55→    }
 56→
 57→    let forge_dir = project_dir.join(FORGE_DIR);
 58→
 59→    // Check if already initialized
 60→    let created = if forge_dir.exists() {
 61→        // Directory exists, ensure structure is complete
 62→        ensure_directory_structure(&forge_dir)?;
 63→        false
 64→    } else {
 65→        // Create new directory structure
 66→        create_directory_structure(&forge_dir)?;
 67→        true
 68→    };
 69→
 70→    Ok(InitResult { forge_dir, created })
 71→}
 72→
 73→/// Create the complete .forge directory structure.
 74→fn create_directory_structure(forge_dir: &Path) -> Result<()> {
 75→    // Create main directory
 76→    std::fs::create_dir_all(forge_dir)
 77→        .with_context(|| format!("Failed to create directory: {}", forge_dir.display()))?;
 78→
 79→    ensure_directory_structure(forge_dir)
 80→}
 81→
 82→/// Ensure all required subdirectories and files exist.
 83→fn ensure_directory_structure(forge_dir: &Path) -> Result<()> {
 84→    // Create subdirectories
 85→    let audit_dir = forge_dir.join("audit");
 86→    let runs_dir = audit_dir.join("runs");
 87→    let prompts_dir = forge_dir.join("prompts");
 88→    let skills_dir = forge_dir.join("skills");
 89→
 90→    std::fs::create_dir_all(&audit_dir)
 91→        .with_context(|| format!("Failed to create audit directory: {}", audit_dir.display()))?;
 92→
 93→    std::fs::create_dir_all(&runs_dir)
 94→        .with_context(|| format!("Failed to create runs directory: {}", runs_dir.display()))?;
 95→
 96→    std::fs::create_dir_all(&prompts_dir).with_context(|| {
 97→        format!(
 98→            "Failed to create prompts directory: {}",
 99→            prompts_dir.display()
100→        )
101→    })?;
102→
103→    std::fs::create_dir_all(&skills_dir).with_context(|| {
104→        format!(
105→            "Failed to create skills directory: {}",
106→            skills_dir.display()
107→        )
108→    })?;
109→
110→    // Create placeholder files if they don't exist
111→    let spec_file = forge_dir.join("spec.md");
112→    if !spec_file.exists() {
113→        std::fs::write(&spec_file, "")
114→            .with_context(|| format!("Failed to create spec.md: {}", spec_file.display()))?;
115→    }
116→
117→    let phases_file = forge_dir.join("phases.json");
118→    if !phases_file.exists() {
119→        std::fs::write(&phases_file, "")
120→            .with_context(|| format!("Failed to create phases.json: {}", phases_file.display()))?;
121→    }
122→
123→    let state_file = forge_dir.join("state");
124→    if !state_file.exists() {
125→        std::fs::write(&state_file, "")
126→            .with_context(|| format!("Failed to create state file: {}", state_file.display()))?;
127→    }
128→
129→    Ok(())
130→}
131→
132→/// Check if a project is already initialized with forge.
133→pub fn is_initialized(project_dir: &Path) -> bool {
134→    project_dir.join(FORGE_DIR).exists()
135→}
136→
137→/// Get the path to the forge directory for a project.
138→pub fn get_forge_dir(project_dir: &Path) -> PathBuf {
139→    project_dir.join(FORGE_DIR)
140→}
141→
142→/// Check if a spec file exists and has content.
143→///
144→/// Returns `true` if `.forge/spec.md` exists and is not empty.
145→pub fn has_spec(project_dir: &Path) -> bool {
146→    let spec_file = project_dir.join(FORGE_DIR).join("spec.md");
147→    if !spec_file.exists() {
148→        return false;
149→    }
150→    match std::fs::read_to_string(&spec_file) {
151→        Ok(content) => !content.trim().is_empty(),
152→        Err(_) => false,
153→    }
154→}
155→
156→/// Check if phases have been generated.
157→///
158→/// Returns `true` if `.forge/phases.json` exists and contains valid JSON.
159→pub fn has_phases(project_dir: &Path) -> bool {
160→    let phases_file = project_dir.join(FORGE_DIR).join("phases.json");
161→    if !phases_file.exists() {
162→        return false;
163→    }
164→    match std::fs::read_to_string(&phases_file) {
165→        Ok(content) => {
166→            if content.trim().is_empty() {
167→                return false;
168→            }
169→            // Try to parse as JSON to verify it's valid
170→            serde_json::from_str::<serde_json::Value>(&content).is_ok()
171→        }
172→        Err(_) => false,
173→    }
174→}
