  2→
  3→use super::summary::{CompactionSummary, IterationContext};
  4→use super::tracker::ContextTracker;
  5→use crate::audit::FileChangeSummary;
  6→use crate::signals::IterationSignals;
  7→use anyhow::Result;
  8→use std::collections::VecDeque;
  9→
 10→/// Maximum number of recent iterations to keep in full detail.
 11→const MAX_RECENT_ITERATIONS: usize = 2;
 12→
 13→/// Manages context compaction for a phase.
 14→///
 15→/// The CompactionManager:
 16→/// 1. Tracks iteration history for potential compaction
 17→/// 2. Decides when to trigger compaction based on context usage
 18→/// 3. Generates summaries that preserve essential context
 19→/// 4. Provides compacted context for prompt injection
 20→#[derive(Debug)]
 21→pub struct CompactionManager {
 22→    /// Phase number being managed.
 23→    phase_number: String,
 24→    /// Phase name.
 25→    phase_name: String,
 26→    /// Promise tag for this phase.
 27→    promise: String,
