 66→    /// Record an iteration's results.
 67→    ///
 68→    /// This method should be called after each Claude iteration to:
 69→    /// 1. Track context usage
 70→    /// 2. Record iteration details for potential compaction
 71→    pub fn record_iteration(
 72→        &mut self,
 73→        iteration: u32,
 74→        prompt_chars: usize,
 75→        output_chars: usize,
 76→        changes: &FileChangeSummary,
 77→        signals: &IterationSignals,
 78→        output_summary: &str,
 79→    ) {
 80→        // Update context tracking
 81→        self.tracker.add_iteration(prompt_chars, output_chars);
 82→
 83→        // Create iteration context
 84→        let mut ctx = IterationContext::new(iteration);
 85→        ctx.summary = output_summary.to_string();
 86→
 87→        // Record file changes
 88→        for path in &changes.files_added {
 89→            ctx.add_new_file(path.clone());
 90→        }
 91→        for path in &changes.files_modified {
 92→            ctx.add_modified_file(path.clone());
 93→        }
 94→
 95→        // Record progress
 96→        ctx.progress_pct = signals.latest_progress();
 97→
 98→        // Record pivots
 99→        for pivot in &signals.pivots {
100→            ctx.add_pivot(&pivot.new_approach);
101→        }
102→
103→        // Record blockers as errors (they indicate issues)
104→        for blocker in &signals.blockers {
105→            if !blocker.acknowledged {
106→                ctx.add_error(&blocker.description);
107→            }
108→        }
109→
110→        // Add to history
111→        self.iteration_history.push_back(ctx);
112→    }
