 28→
 29→/// Run the implement command.
 30→///
 31→/// This is the main entry point for `forge implement <design-doc>`.
 32→///
 33→/// # Arguments
 34→/// * `project_dir` - The project root directory
 35→/// * `design_doc` - Path to the design document
 36→/// * `no_tdd` - Skip test phase generation
 37→/// * `dry_run` - Generate spec and phases without executing
 38→///
 39→/// # Returns
 40→/// `Ok(())` on success, or an error if something fails.
 41→pub fn run_implement(
 42→    project_dir: &Path,
 43→    design_doc: &Path,
 44→    no_tdd: bool,
 45→    dry_run: bool,
 46→) -> Result<()> {
 47→    // 1. Validate and read design doc
 48→    println!("Parsing design doc...");
 49→    let design_content = validate_design_doc(design_doc)?;
 50→
 51→    // 2. Extract structure via Claude
 52→    println!("Extracting implementation details...");
 53→    let extracted = extract_design(project_dir, &design_content, design_doc)?;
 54→
 55→    // 3. Filter out test phases if --no-tdd and renumber
 56→    let phases = filter_phases(extracted.phases, no_tdd);
 57→
 58→    // 4. Generate spec.md
 59→    println!("Generating implementation spec...");
 60→    let spec_content = generate_spec_markdown(&extracted.spec);
 61→    let forge_dir = get_forge_dir(project_dir);
 62→
 63→    // Ensure .forge directory exists
 64→    if !forge_dir.exists() {
 65→        std::fs::create_dir_all(&forge_dir).context("Failed to create .forge directory")?;
 66→    }
 67→
 68→    std::fs::write(forge_dir.join("spec.md"), &spec_content).context("Failed to write spec.md")?;
 69→
 70→    // 5. Save phases.json
 71→    println!("Generating phases...");
 72→    let phases_file = create_phases_file(phases.clone(), &spec_content);
 73→    phases_file
 74→        .save(&forge_dir.join("phases.json"))
 75→        .context("Failed to write phases.json")?;
 76→
 77→    // 6. Display phases
 78→    display_phases_with_type(&phases);
 79→
 80→    if dry_run {
 81→        println!();
 82→        println!("Dry run complete. Review:");
 83→        println!("  Spec: .forge/spec.md");
 84→        println!("  Phases: .forge/phases.json");
 85→        return Ok(());
 86→    }
 87→
 88→    // 7. Interactive review
 89→    loop {
 90→        println!("[a]pprove  [e]dit phase  [r]egenerate  [q]uit");
 91→
 92→        let input: String = Input::new()
 93→            .with_prompt(">")
 94→            .allow_empty(false)
 95→            .interact_text()
 96→            .context("Failed to read user input")?;
 97→
 98→        match parse_review_action(&input)? {
 99→            ReviewAction::Approve => {
100→                println!();
101→                println!("Phases approved. Run 'forge run' to start execution.");
102→                return Ok(());
103→            }
104→            ReviewAction::EditPhase(phase_num) => {
105→                println!(
106→                    "\nEditing phase {} - please provide feedback and regenerate.",
107→                    phase_num
108→                );
109→                println!("Phase editing is not yet fully implemented.");
110→                continue;
111→            }
112→            ReviewAction::Regenerate => {
113→                println!("\nRegenerating...");
114→                // Re-extract
115→                let extracted = extract_design(project_dir, &design_content, design_doc)?;
116→                let phases = filter_phases(extracted.phases, no_tdd);
117→
118→                // Update spec and phases
119→                let spec_content = generate_spec_markdown(&extracted.spec);
120→                std::fs::write(forge_dir.join("spec.md"), &spec_content)
121→                    .context("Failed to write spec.md during regeneration")?;
122→
123→                let phases_file = create_phases_file(phases.clone(), &spec_content);
124→                phases_file
125→                    .save(&forge_dir.join("phases.json"))
126→                    .context("Failed to write phases.json during regeneration")?;
127→
128→                display_phases_with_type(&phases);
129→                continue;
130→            }
131→            ReviewAction::Quit => {
132→                println!("\nExiting without changes.");
133→                return Ok(());
134→            }
135→        }
136→    }
137→}
