139→/// Display phases with their type (test/implement) indicator.
140→fn display_phases_with_type(phases: &[Phase]) {
141→    println!();
142→    for phase in phases {
143→        let type_tag = match phase.phase_type {
144→            Some(PhaseType::Test) => "[test]",
145→            Some(PhaseType::Implement) => "[implement]",
146→            None => "",
147→        };
148→
149→        println!(
150→            "Phase {}: {} (budget: {}) {}",
151→            phase.number, phase.name, phase.budget, type_tag
152→        );
153→    }
154→    println!();
155→}
