157→/// Filter phases based on TDD setting and renumber them.
158→///
159→/// If `no_tdd` is true, test phases are filtered out.
160→/// The remaining phases are then renumbered sequentially.
161→fn filter_phases(phases: Vec<Phase>, no_tdd: bool) -> Vec<Phase> {
162→    let filtered = if no_tdd {
163→        phases
164→            .into_iter()
165→            .filter(|p| p.phase_type != Some(PhaseType::Test))
166→            .collect()
167→    } else {
168→        phases
169→    };
170→    renumber_phases(filtered)
171→}
172→
173→/// Renumber phases sequentially after filtering.
174→///
175→/// When --no-tdd filters out test phases, we need to renumber
176→/// the remaining phases to be sequential (01, 02, 03...) and
177→/// update their dependencies accordingly.
178→fn renumber_phases(phases: Vec<Phase>) -> Vec<Phase> {
179→    if phases.is_empty() {
180→        return phases;
181→    }
182→
183→    // Build a mapping from old number to new number
184→    let mut number_map: std::collections::HashMap<String, String> =
185→        std::collections::HashMap::new();
186→    for (i, phase) in phases.iter().enumerate() {
187→        let new_number = format!("{:02}", i + 1);
188→        number_map.insert(phase.number.clone(), new_number);
189→    }
190→
191→    // Apply the mapping
192→    phases
193→        .into_iter()
194→        .enumerate()
195→        .map(|(i, mut phase)| {
196→            let new_number = format!("{:02}", i + 1);
197→
198→            // Update dependencies to use new numbers
199→            phase.depends_on = phase
200→                .depends_on
201→                .into_iter()
202→                .filter_map(|dep| number_map.get(&dep).cloned())
203→                .collect();
204→
205→            phase.number = new_number;
206→            phase
207→        })
208→        .collect()
209→}
