 67→/// Builder for iteration feedback injected via `--append-system-prompt`.
 68→///
 69→/// Aggregates status, git changes, and signals from the prior iteration
 70→/// into a compact system prompt that gives Claude context about its progress.
 71→pub struct IterationFeedback {
 72→    parts: Vec<String>,
 73→}
 74→
 75→impl Default for IterationFeedback {
 76→    fn default() -> Self {
 77→        Self::new()
 78→    }
 79→}
 80→
 81→impl IterationFeedback {
 82→    pub fn new() -> Self {
 83→        Self { parts: Vec::new() }
 84→    }
 85→
 86→    /// Add iteration status (current iteration, budget, whether promise was found).
 87→    pub fn with_iteration_status(
 88→        mut self,
 89→        iteration: u32,
 90→        budget: u32,
 91→        promise_found: bool,
 92→    ) -> Self {
 93→        let status = if promise_found {
 94→            "COMPLETED".to_string()
 95→        } else {
 96→            format!("in progress ({}/{})", iteration, budget)
 97→        };
 98→        self.parts.push(format!("Iteration status: {}", status));
 99→        self
100→    }

100→    }
101→
102→    /// Add git change summary from the prior iteration.
103→    pub fn with_git_changes(mut self, changes: &FileChangeSummary) -> Self {
104→        if changes.is_empty() {
105→            return self;
106→        }
107→        let mut lines = vec![format!(
108→            "Files changed: {} added, {} modified, {} deleted (+{}/-{})",
109→            changes.files_added.len(),
110→            changes.files_modified.len(),
111→            changes.files_deleted.len(),
112→            changes.total_lines_added,
113→            changes.total_lines_removed,
114→        )];
115→        // Show up to 10 modified files
116→        for path in changes.files_modified.iter().take(10) {
117→            lines.push(format!("  M {}", path.display()));
118→        }
119→        for path in changes.files_added.iter().take(5) {
120→            lines.push(format!("  A {}", path.display()));
121→        }
122→        self.parts.push(lines.join("\n"));
123→        self
124→    }
125→
126→    /// Add signals from the prior iteration (progress %, blockers).
127→    /// Pivots are intentionally excluded here — use `with_pivot()` instead,
128→    /// which renders them as a prominent `## STRATEGY CHANGE` directive.
129→    pub fn with_signals(mut self, signals: &IterationSignals) -> Self {
130→        if !signals.has_signals() {
131→            return self;
132→        }
133→        let mut lines = Vec::new();
134→        if let Some(pct) = signals.latest_progress() {
135→            lines.push(format!("Progress: {}%", pct));
136→        }
137→        for blocker in &signals.blockers {
138→            if !blocker.acknowledged {
139→                lines.push(format!("Blocker: {}", blocker.description));
140→            }
141→        }
142→        if !lines.is_empty() {
143→            self.parts.push(lines.join("\n"));
144→        }
145→        self
146→    }
147→
148→    /// Inject a pivot signal as a prominent strategy-change directive.
149→    ///
150→    /// When Claude emits `<pivot>`, the new approach must override the prior
151→    /// strategy. Rendered as a `## STRATEGY CHANGE` block so it appears as an
152→    /// instruction rather than an informational note.
153→    pub fn with_pivot(mut self, pivot_text: &str) -> Self {
154→        self.parts.push(format!(
155→            "## STRATEGY CHANGE\nYou previously signalled a strategy change:\n\
156→             \"{}\"\nYou MUST follow this new approach in this iteration. \
157→             Do not repeat the prior approach.",
158→            pivot_text
159→        ));
160→        self
161→    }
162→
163→    /// Build the feedback string. Returns None if no content was added.
164→    ///
165→    /// ## Why feedback is injected as system prompt context
166→    ///
167→    /// Claude is invoked as a subprocess; the only ergonomic channel for
168→    /// structured per-iteration context is `--append-system-prompt`. Injecting
169→    /// here means the feedback arrives before the user-turn prompt, giving
170→    /// Claude a reliable "briefing" section it can reference without modifying
171→    /// the task prompt itself.
172→    ///
173→    /// ## Why the 4 000-character limit exists
174→    ///
175→    /// The feedback block is appended to the system prompt on *every* iteration.
176→    /// Without a cap, a phase with many file changes or a verbose blocker
177→    /// description could double the size of the system prompt, consuming
178→    /// context window tokens that Claude needs for actual work. 4 000 chars
179→    /// is roughly 1 000 tokens — large enough for meaningful signal, small
180→    /// enough not to crowd out the spec and task sections.
181→    ///
182→    /// ## What is prioritised when truncating
183→    ///
184→    /// Parts are joined in the order they were added: iteration status first,
185→    /// then git changes, then signals (progress %, blockers), and finally any
186→    /// pivot directive. Truncation cuts the trailing characters of the
187→    /// concatenated string, so higher-priority parts (status, git summary)
188→    /// survive intact while verbose tails (e.g., long file lists) are trimmed.
189→    pub fn build(self) -> Option<String> {
190→        if self.parts.is_empty() {
191→            return None;
192→        }
193→        let mut result = String::from("## ITERATION FEEDBACK\n");
194→        result.push_str(&self.parts.join("\n\n"));
195→
196→        // Truncate to 4000 chars max to prevent doubling the system prompt
197→        // size. The trailing "..." signals to Claude that output was clipped.
198→        if result.len() > 4000 {
199→            result.truncate(3997);
200→            result.push_str("...");
201→        }
202→        Some(result)
203→    }
204→}
205→
206→/// Extract token usage from a parsed Claude CLI result event.
207→/// Returns `None` if the value is not a `result`-type event or lacks
208→/// the expected `usage.input_tokens`/`usage.output_tokens` fields.
209→/// Note: token counts are capped at u32::MAX.
210→fn extract_token_usage(parsed: &serde_json::Value) -> Option<TokenUsage> {
211→    if parsed.get("type")?.as_str()? == "result" {
212→        let usage = parsed.get("usage")?;
213→        Some(TokenUsage {
214→            input_tokens: usage
215→                .get("input_tokens")?
216→                .as_u64()?
217→                .try_into()
218→                .unwrap_or(u32::MAX),
219→            output_tokens: usage
220→                .get("output_tokens")?
221→                .as_u64()?
222→                .try_into()
223→                .unwrap_or(u32::MAX),
224→        })
225→    } else {
226→        None
227→    }
228→}
229→
230→fn aggregate_council_token_usage(council_result: &CouncilPhaseResult) -> Option<TokenUsage> {
231→    let mut input_tokens = 0u64;
232→    let mut output_tokens = 0u64;
233→    let mut saw_usage = false;
234→
235→    for usage in council_result
236→        .worker_results
237→        .iter()
238→        .filter_map(|worker| worker.token_usage.as_ref())
239→    {
240→        saw_usage = true;
241→        input_tokens += u64::from(usage.input_tokens);
242→        output_tokens += u64::from(usage.output_tokens);
243→    }
244→
245→    saw_usage.then(|| TokenUsage {
246→        input_tokens: input_tokens.min(u64::from(u32::MAX)) as u32,
247→        output_tokens: output_tokens.min(u64::from(u32::MAX)) as u32,
248→    })
249→}

